namespace UnifiedToolkit.Conversion.Mapping.Upgrades;
public static class UpgradeMappingValidator { public static IReadOnlyList<string> Validate(IEnumerable<UpgradeMapping> mappings,IEnumerable<UpgradeSourceAlternate> alternates){var ms=mappings.ToList();var al=alternates.ToList();var issues=new List<string>();AddDup(ms.Select(x=>x.MappingId),"mapping ID",issues);AddDup(ms.Select(x=>x.SourceId),"canonical source ID",issues);AddDup(ms.Select(x=>$"{x.TargetId}|{x.Slot}|{string.Join(';',x.Factions.OrderBy(y=>y))}|{string.Join(';',x.ShipRestrictions.OrderBy(y=>y))}"),"semantic target identity",issues);AddDup(al.Select(x=>x.SourceId),"alternate source ID",issues);var canonical=ms.Select(x=>x.SourceId).ToHashSet(StringComparer.OrdinalIgnoreCase);foreach(var a in al){if(!canonical.Contains(a.CanonicalSourceId))issues.Add($"Alternate source '{a.SourceId}' references unknown canonical source '{a.CanonicalSourceId}'.");if(canonical.Contains(a.SourceId))issues.Add($"Source '{a.SourceId}' is both canonical and alternate.");}return issues;}private static void AddDup(IEnumerable<string> values,string label,List<string> issues){foreach(var g in values.Where(x=>!string.IsNullOrWhiteSpace(x)).GroupBy(x=>x,StringComparer.OrdinalIgnoreCase).Where(x=>x.Count()>1))issues.Add($"Duplicate upgrade {label} '{g.Key}'.");}}
